     2→using System;
     3→using System.Text.Json;
     4→using System.Threading;
     5→using System.Threading.Tasks;
     6→using FluentAssertions;
     7→using Moq;
     8→using Xunit;
     9→using Polly;
    10→using Polly.Retry;
    11→
    12→namespace PaletteStream.ETL.Tests.Architecture
    13→{
    14→    #region Contracts ──────────────────────────────────────────────────────────
    15→    /// <summary>
    16→    /// Basic abstraction for a Kafka-like producer.
    17→    /// </summary>
    18→    /// <typeparam name="TKey">Key type.</typeparam>
    19→    /// <typeparam name="TValue">Value type.</typeparam>
    20→    public interface IKafkaProducer<in TKey, in TValue>
    21→    {
    22→        Task ProduceAsync(string topic, TKey key, TValue value, CancellationToken ct = default);
    23→    }
    24→
    25→    /// <summary>
    26→    /// Represents an ETL domain event.
    27→    /// </summary>
    28→    public interface IDomainEvent
    29→    {
    30→        Guid EventId { get; }
    31→        DateTimeOffset OccurredOn { get; }
    32→        string EventType { get; }
    33→    }
    34→
    35→    /// <summary>
    36→    /// Sink for messages that could not be published to the primary topic.
    37→    /// </summary>
    38→    public interface IDeadLetterSink
    39→    {
    40→        Task SendAsync(byte[] message, CancellationToken ct = default);
    41→    }
    42→    #endregion
    43→
    44→    #region Implementation ────────────────────────────────────────────────────
    45→    /// <summary>
    46→    /// Publishes <see cref="IDomainEvent"/> instances to Kafka with retry +
    47→    /// back-off and a dead-letter fallback.
    48→    /// </summary>
    49→    public sealed class EventPublisher
    50→    {
    51→        private const string DefaultTopic = "etl-domain-events";
    52→
    53→        private readonly IKafkaProducer<string, byte[]> _producer;
    54→        private readonly IDeadLetterSink _deadLetterSink;
    55→        private readonly AsyncRetryPolicy _retryPolicy;
    56→
    57→        public EventPublisher(
    58→            IKafkaProducer<string, byte[]> producer,
    59→            IDeadLetterSink deadLetterSink,
    60→            int retryCount = 3)
    61→        {
    62→            _producer = producer ?? throw new ArgumentNullException(nameof(producer));
    63→            _deadLetterSink = deadLetterSink ?? throw new ArgumentNullException(nameof(deadLetterSink));
    64→
    65→            _retryPolicy = Policy
    66→                .Handle<Exception>() // Capture any broker/transport exceptions.
    67→                .WaitAndRetryAsync(
    68→                    retryCount,
    69→                    retryAttempt => TimeSpan.FromMilliseconds(Math.Pow(2, retryAttempt) * 100),
    70→                    onRetry: (ex, ts, i, _) =>
    71→                    {
    72→                        // In production we'd emit a structured log entry here.
    73→                        Console.WriteLine(
    74→                            $"Retry {i} after {ts.TotalMilliseconds:n0} ms due to: {ex.Message}");
    75→                    });
    76→        }
    77→
    78→        public async Task PublishAsync(IDomainEvent domainEvent, CancellationToken ct = default)
    79→        {
    80→            if (domainEvent == null) throw new ArgumentNullException(nameof(domainEvent));
    81→
    82→            var serialized = JsonSerializer.SerializeToUtf8Bytes(domainEvent, domainEvent.GetType());
    83→
    84→            try
    85→            {
    86→                await _retryPolicy.ExecuteAsync(
    87→                    async token => await _producer.ProduceAsync(
    88→                        DefaultTopic,
    89→                        domainEvent.EventId.ToString("N"),
    90→                        serialized,
    91→                        token),
    92→                    ct);
    93→            }
    94→            catch (Exception finalEx)
    95→            {
    96→                // Fallback to dead-letter sink.
    97→                await _deadLetterSink.SendAsync(serialized, ct);
    98→
    99→                // Bubble up so that calling code can still be aware something went wrong.
   100→                throw new EventPublishException(
   101→                    $"Failed to publish event {domainEvent.EventId}", finalEx);
   102→            }
   103→        }
   104→    }
   105→
   106→    /// <summary>
   107→    /// Exception thrown when an event could not be published.
   108→    /// </summary>
   109→    public sealed class EventPublishException : Exception
   110→    {
   111→        public EventPublishException(string message, Exception inner)
   112→            : base(message, inner) { }
   113→    }
   114→    #endregion
   115→
   116→    #region Dummy Domain Event ────────────────────────────────────────────────
   117→    private sealed class DataPigmentTransformedEvent : IDomainEvent
   118→    {
   119→        public Guid EventId { get; } = Guid.NewGuid();
   120→        public DateTimeOffset OccurredOn { get; } = DateTimeOffset.UtcNow;
   121→        public string EventType => nameof(DataPigmentTransformedEvent);
   122→
   123→        public string PigmentName { get; init; } = default!;
   124→        public string Transformation { get; init; } = default!;
   125→        public string Operator { get; init; } = default!;
   126→    }
   127→    #endregion
   128→
   129→    #region Tests ─────────────────────────────────────────────────────────────
   130→    public class EventPublisherTests
   131→    {
   132→        private readonly Mock<IKafkaProducer<string, byte[]>> _producerMock =
   133→            new(MockBehavior.Strict);
   134→
   135→        private readonly Mock<IDeadLetterSink> _deadLetterMock =
   136→            new(MockBehavior.Strict);
   137→
   138→        private EventPublisher BuildSut(int retryCount = 3)
   139→            => new(_producerMock.Object, _deadLetterMock.Object, retryCount);
   140→
   141→        private static DataPigmentTransformedEvent CreateSampleEvent()
   142→            => new()
   143→            {
   144→                PigmentName = "Cerulean",
   145→                Transformation = "Aggregation",
   146→                Operator = "GPU-Blend"
   147→            };
   148→
   149→        [Fact(DisplayName = "PublishAsync sends event to correct topic with key/value")]
   150→        public async Task PublishAsync_SendsMessage_WhenFirstTrySucceeds()
   151→        {
   152→            // Arrange
   153→            var sut = BuildSut();
   154→            var sample = CreateSampleEvent();
   155→
   156→            _producerMock
   157→                .Setup(p => p.ProduceAsync(
   158→                    It.Is<string>(t => t == "etl-domain-events"),
   159→                    It.Is<string>(k => k == sample.EventId.ToString("N")),
   160→                    It.IsAny<byte[]>(),
   161→                    It.IsAny<CancellationToken>()))
   162→                .Returns(Task.CompletedTask)
   163→                .Verifiable();
   164→
   165→            // No calls expected to dead-letter sink.
   166→            _deadLetterMock.VerifyNoOtherCalls();
   167→
   168→            // Act
   169→            await sut.PublishAsync(sample);
   170→
   171→            // Assert
   172→            _producerMock.Verify(); // Ensures the expected interaction occurred.
   173→        }
   174→
   175→        [Fact(DisplayName = "PublishAsync retries and eventually succeeds")]
   176→        public async Task PublishAsync_RetriesAndSucceeds_BeforeExhaustingPolicy()
   177→        {
   178→            // Arrange
   179→            var sut = BuildSut(retryCount: 2);
   180→            var sample = CreateSampleEvent();
   181→            var attempt = 0;
   182→
   183→            _producerMock
   184→                .Setup(p => p.ProduceAsync(
   185→                    It.IsAny<string>(),
   186→                    It.IsAny<string>(),
   187→                    It.IsAny<byte[]>(),
   188→                    It.IsAny<CancellationToken>()))
   189→                .Returns(() =>
   190→                {
   191→                    attempt++;
   192→                    // Fail first attempt only
   193→                    if (attempt == 1) throw new TimeoutException("Simulated broker timeout");
   194→                    return Task.CompletedTask;
   195→                });
   196→
   197→            // Act
   198→            await sut.PublishAsync(sample);
   199→
   200→            // Assert
   201→            attempt.Should().Be(2, "one retry should have been performed");
   202→            _deadLetterMock.VerifyNoOtherCalls();
   203→        }
   204→
   205→        [Fact(DisplayName = "PublishAsync pushes to dead-letter sink after all retries fail")]
   206→        public async Task PublishAsync_GoesToDeadLetter_WhenRetriesExhausted()
   207→        {
   208→            // Arrange
   209→            var sut = BuildSut(retryCount: 2);
   210→            var sample = CreateSampleEvent();
   211→
   212→            _producerMock
   213→                .Setup(p => p.ProduceAsync(
   214→                    It.IsAny<string>(),
   215→                    It.IsAny<string>(),
   216→                    It.IsAny<byte[]>(),
   217→                    It.IsAny<CancellationToken>()))
   218→                .ThrowsAsync(new InvalidOperationException("Permanent failure"));
   219→
   220→            _deadLetterMock
   221→                .Setup(d => d.SendAsync(
   222→                    It.IsAny<byte[]>(),
   223→                    It.IsAny<CancellationToken>()))
   224→                .Returns(Task.CompletedTask)
   225→                .Verifiable();
   226→
   227→            // Act
   228→            Func<Task> act = () => sut.PublishAsync(sample);
   229→
   230→            // Assert
   231→            await act.Should().ThrowAsync<EventPublishException>();
   232→            _deadLetterMock.Verify();
   233→        }
   234→    }
   235→    #endregion
   236→}
