    33→
    34→    /// <summary>
    35→    /// A single unit of data transported through the ETL pipeline
    36→    /// </summary>
    37→    public sealed record DataPigment(Guid Id, IReadOnlyDictionary<string, object> Payload);
    38→
    39→    /// <summary>
    40→    /// Marker interface for pipeline stages.
    41→    /// </summary>
