    47→    /// <summary>
    48→    /// Each stage can publish domain events via the event bus.
    49→    /// The functional code base provides an implementation – for the tests we create a lightweight stub.
    50→    /// </summary>
    51→    public interface IEventBus
    52→    {
    53→        void Publish<TEvent>(TEvent @event) where TEvent : IPipelineEvent;
    54→        void Subscribe<TEvent>(Action<TEvent> handler) where TEvent : IPipelineEvent;
    55→    }
