    66→    internal record IngestedEvent(Guid PigmentId, DateTimeOffset Timestamp)  : IPipelineEvent;
    67→    internal record TransformedEvent(Guid PigmentId, DateTimeOffset Timestamp) : IPipelineEvent;
    68→    internal record LoadedEvent(Guid PigmentId, DateTimeOffset Timestamp) : IPipelineEvent;
