    75→    /// <summary>
    76→    ///  In-memory event-bus used only for tests. Thread-safe, minimalistic and deterministic.
    77→    /// </summary>
    78→    internal sealed class InMemoryEventBus : IEventBus
    79→    {
    80→        private readonly ConcurrentDictionary<Type, List<Delegate>> _subscriptions = new();
    81→
    82→        public void Publish<TEvent>(TEvent @event) where TEvent : IPipelineEvent
    83→        {
    84→            if (_subscriptions.TryGetValue(typeof(TEvent), out var handlers))
    85→            {
    86→                // Clone to avoid concurrency issues while enumerating.
    87→                var snapshot = handlers.ToArray();
    88→                foreach (var handler in snapshot.Cast<Action<TEvent>>())
    89→                {
    90→                    handler(@event);
    91→                }
    92→            }
    93→        }
    94→
    95→        public void Subscribe<TEvent>(Action<TEvent> handler) where TEvent : IPipelineEvent
    96→        {
    97→            _subscriptions.AddOrUpdate(
    98→                typeof(TEvent),
    99→                _ => new List<Delegate> { handler },
   100→                (_, list) =>
   101→                {
   102→                    list.Add(handler);
   103→                    return list;
   104→                });
   105→        }
   106→    }
