   108→    /// <summary>
   109→    ///  Simple pipeline orchestrator that executes stages sequentially and surfaces events via IEventBus.
   110→    /// </summary>
   111→    internal sealed class EtlPipeline
   112→    {
   113→        private readonly IEnumerable<IPipelineStage> _stages;
   114→        private readonly IEventBus _eventBus;
   115→
   116→        public EtlPipeline(IEnumerable<IPipelineStage> stages, IEventBus eventBus)
   117→        {
   118→            _stages   = stages ?? throw new ArgumentNullException(nameof(stages));
   119→            _eventBus = eventBus ?? throw new ArgumentNullException(nameof(eventBus));
   120→        }
   121→
   122→        public async Task<DataPigment> ExecuteAsync(DataPigment pigment, CancellationToken ct = default)
   123→        {
   124→            _eventBus.Publish(new IngestedEvent(pigment.Id, DateTimeOffset.UtcNow));
   125→
   126→            var current = pigment;
   127→            foreach (var stage in _stages)
   128→            {
   129→                try
   130→                {
   131→                    current = await stage.ProcessAsync(current, ct).ConfigureAwait(false);
   132→                    _eventBus.Publish(new TransformedEvent(current.Id, DateTimeOffset.UtcNow));
   133→                }
   134→                catch (Exception ex)
   135→                {
   136→                    _eventBus.Publish(new ErrorEvent(current.Id, DateTimeOffset.UtcNow, stage.GetType().Name, ex));
   137→                    throw; // let the orchestrator bubble the exception so the caller can react.
   138→                }
   139→            }
   140→
   141→            _eventBus.Publish(new LoadedEvent(current.Id, DateTimeOffset.UtcNow));
   142→            return current;
   143→        }
   144→    }
