   150→    public sealed class DataFlowAndEventContractTests
   151→    {
   152→        private static DataPigment GeneratePigment() =>
   153→            new(Guid.NewGuid(), new Dictionary<string, object> { ["input"] = "raw-value" });
   154→
   155→        [Fact(DisplayName = "Pipeline publishes Ingested, a Transformed per stage, then Loaded events in order")]
   156→        public async Task PipelinePublishesKeyEventsInExpectedOrder()
   157→        {
   158→            // Arrange ----------------------------------------------------------
   159→            var bus = new InMemoryEventBus();
   160→            var observedEvents = new List<IPipelineEvent>();
   161→
   162→            bus.Subscribe<IngestedEvent>(e   => observedEvents.Add(e));
   163→            bus.Subscribe<TransformedEvent>(e => observedEvents.Add(e));
   164→            bus.Subscribe<LoadedEvent>(e      => observedEvents.Add(e));
   165→
   166→            // Two trivial mock stages
   167→            var stage1 = new Mock<IPipelineStage>();
   168→            var stage2 = new Mock<IPipelineStage>();
   169→
   170→            stage1.Setup(s => s.ProcessAsync(It.IsAny<DataPigment>(), It.IsAny<CancellationToken>()))
   171→                  .ReturnsAsync((DataPigment p, CancellationToken _) =>
   172→                      p with { Payload = p.Payload.Append("stage1", "ok") });
   173→
   174→            stage2.Setup(s => s.ProcessAsync(It.IsAny<DataPigment>(), It.IsAny<CancellationToken>()))
   175→                  .ReturnsAsync((DataPigment p, CancellationToken _) =>
   176→                      p with { Payload = p.Payload.Append("stage2", "ok") });
   177→
   178→            var pipeline = new EtlPipeline(new[] { stage1.Object, stage2.Object }, bus);
   179→
   180→            // Act --------------------------------------------------------------
   181→            var pigment = GeneratePigment();
   182→            await pipeline.ExecuteAsync(pigment);
   183→
   184→            // Assert -----------------------------------------------------------
   185→            observedEvents.Should().HaveCount(1 /*ingested*/ + 2 /*transforms*/ + 1 /*loaded*/);
   186→
   187→            observedEvents.Select(e => e switch
   188→            {
   189→                IngestedEvent   => "Ingested",
   190→                TransformedEvent=> "Transformed",
   191→                LoadedEvent     => "Loaded",
   192→                _               => "Unknown"
   193→            })
   194→            .Should()
   195→            .ContainInOrder("Ingested", "Transformed", "Transformed", "Loaded");
   196→        }
   197→
   198→        [Fact(DisplayName = "Subscribers receive each event exactly once even under concurrent load")]
   199→        public async Task EventBusDispatchesToAllSubscribersExactlyOnce()
   200→        {
   201→            // Arrange ----------------------------------------------------------
   202→            var bus = new InMemoryEventBus();
   203→
   204→            var ingestedCount  = 0;
   205→            var transformedCount = 0;
   206→            var loadedCount    = 0;
   207→
   208→            bus.Subscribe<IngestedEvent>(_ => Interlocked.Increment(ref ingestedCount));
   209→            bus.Subscribe<TransformedEvent>(_ => Interlocked.Increment(ref transformedCount));
   210→            bus.Subscribe<LoadedEvent>(_ => Interlocked.Increment(ref loadedCount));
   211→
   212→            var stage = new Mock<IPipelineStage>();
   213→            stage.Setup(s => s.ProcessAsync(It.IsAny<DataPigment>(), It.IsAny<CancellationToken>()))
   214→                 .ReturnsAsync((DataPigment p, CancellationToken _) => p);
   215→
   216→            var pipeline = new EtlPipeline(Enumerable.Repeat(stage.Object, 3), bus);
   217→
   218→            // Act --------------------------------------------------------------
   219→            const int parallelRuns = 25;
   220→            await Task.WhenAll(Enumerable.Range(0, parallelRuns)
   221→                .Select(_ => pipeline.ExecuteAsync(GeneratePigment())));
   222→
   223→            // Assert -----------------------------------------------------------
   224→            ingestedCount.Should().Be(parallelRuns);
   225→            transformedCount.Should().Be(parallelRuns * 3);
   226→            loadedCount.Should().Be(parallelRuns);
   227→        }
   228→
   229→        [Fact(DisplayName = "Error in a stage raises ErrorEvent and propagates exception")]
   230→        public async Task PipelinePublishesErrorEventWhenStageFails()
   231→        {
   232→            // Arrange ----------------------------------------------------------
   233→            var bus = new InMemoryEventBus();
   234→            var errorEvents = new ConcurrentBag<ErrorEvent>();
   235→            bus.Subscribe<ErrorEvent>(errorEvents.Add);
   236→
   237→            var failingStage = new Mock<IPipelineStage>();
