   239→                        .ThrowsAsync(new InvalidOperationException("Boom"));
   240→
   241→            var pipeline = new EtlPipeline(new[] { failingStage.Object }, bus);
   242→
   243→            // Act --------------------------------------------------------------
   244→            Func<Task> act = () => pipeline.ExecuteAsync(GeneratePigment());
   245→
   246→            // Assert -----------------------------------------------------------
