   248→                     .WithMessage("Boom");
   249→
   250→            errorEvents.Should().HaveCount(1);
   251→            var evt = errorEvents.Single();
   252→            evt.Stage.Should().Be(failingStage.Object.GetType().Name);
   253→            evt.Error.Should().BeOfType<InvalidOperationException>();
   254→        }
   255→    }
