   277→        public static T WithTracing<T>(this T @event) where T : IDataEvent
   278→        {
   279→            var activity = Activity.Current;
   280→            if (activity == null) return @event;
   281→
   282→            var tags = @event.Tags.ToDictionary(kv => kv.Key, kv => kv.Value, StringComparer.OrdinalIgnoreCase);
   283→            tags["trace_id"] = activity.TraceId.ToString();
   284→            tags["span_id"]  = activity.SpanId.ToString();
   285→
   286→            return @event switch
