   289→                DataValidationFailedEvent e     => e with { Tags = tags },
   290→                DataTransformAppliedEvent e     => e with { Tags = tags },
   291→                DataQualityCheckFailedEvent e   => e with { Tags = tags },
   292→                DataBatchCompletedEvent e       => e with { Tags = tags },
   293→                PipelineErrorEvent e            => e with { Tags = tags },
   294→                _                               => @event
