    32→namespace PaletteStream.Transformer.Core
    33→{
    34→    /// <summary>
    35→    /// Represents the background service responsible for orchestrating the
    36→    /// end-to-end data transformation lifecycle.
    37→    /// </summary>
    38→    public sealed class TransformationWorker : BackgroundService
    39→    {
    40→        private readonly ILogger<TransformationWorker> _logger;
    41→        private readonly ITransformationSource _source;
    42→        private readonly ITransformationSink _sink;
    43→        private readonly ITransformationStrategyFactory _strategyFactory;
    44→        private readonly IReadOnlyCollection<ITransformationObserver> _observers;
    45→        private readonly IDataQualityService _dataQualityService;
    46→
    47→        public TransformationWorker(
    48→            ILogger<TransformationWorker> logger,
    49→            ITransformationSource source,
    50→            ITransformationSink sink,
    51→            ITransformationStrategyFactory strategyFactory,
    52→            IEnumerable<ITransformationObserver> observers,
    53→            IDataQualityService dataQualityService)
    54→        {
    55→            _logger             = logger ?? throw new ArgumentNullException(nameof(logger));
    56→            _source             = source ?? throw new ArgumentNullException(nameof(source));
    57→            _sink               = sink ?? throw new ArgumentNullException(nameof(sink));
    58→            _strategyFactory    = strategyFactory ?? throw new ArgumentNullException(nameof(strategyFactory));
    59→            _dataQualityService = dataQualityService ?? throw new ArgumentNullException(nameof(dataQualityService));
    60→            _observers          = observers is IReadOnlyCollection<ITransformationObserver> list 
    61→                                      ? list
    62→                                      : new List<ITransformationObserver>(observers ?? Array.Empty<ITransformationObserver>());
    63→        }
