    56→        {
    57→            _logger.LogInformation("LoaderWorker started with {Parallelism} parallelism.", _options.MaxDegreeOfParallelism);
    58→
    59→            // Fire-and-forget pump from queue -> channel.
    60→            _ = Task.Run(() => PumpQueueAsync(stoppingToken), stoppingToken);
    61→
    62→            // Spin up consumer tasks
    63→            var consumers = new List<Task>();
    64→            for (var i = 0; i < _options.MaxDegreeOfParallelism; i++)
    65→            {
    66→                consumers.Add(Task.Run(() => ConsumeChannelAsync(i, stoppingToken), stoppingToken));
