    92→    /// <summary>
    93→    /// Implements builder pattern for composing complex transformation pipelines.
    94→    /// </summary>
    95→    public sealed class PipelineBuilder
    96→    {
    97→        private readonly List<Func<IServiceProvider, IPipelineStage>> _factoryDelegates = new();
    98→        private readonly List<ITransformationObserver> _observers = new();
    99→        private readonly IServiceProvider _services;
   100→        private readonly ILogger<PipelineBuilder> _logger;
   101→        private bool _built;
   102→
   103→        public PipelineBuilder(IServiceProvider services)
   104→        {
   105→            _services = services ?? throw new ArgumentNullException(nameof(services));
   106→            _logger = _services.GetRequiredService<ILogger<PipelineBuilder>>();
   107→        }
   108→
   109→        /// <summary>
   110→        /// Adds a new stage to the pipeline. The stage is resolved from the container.
   111→        /// </summary>
   112→        public PipelineBuilder AddStage<TStage>() where TStage : class, IPipelineStage
   113→        {
   114→            EnsureNotBuilt();
   115→            _factoryDelegates.Add(sp => sp.GetRequiredService<TStage>());
   116→            _logger.LogDebug("Queued stage {StageType}", typeof(TStage).Name);
   117→            return this;
   118→        }
   119→
   120→        /// <summary>
   121→        /// Adds a stage using a custom factory delegate.
   122→        /// </summary>
   123→        public PipelineBuilder AddStage<TStage>(Func<IServiceProvider, TStage> factory)
   124→            where TStage : class, IPipelineStage
   125→        {
   126→            if (factory is null)
   127→                throw new ArgumentNullException(nameof(factory));
   128→
   129→            EnsureNotBuilt();
   130→            _factoryDelegates.Add(sp => factory(sp));
   131→            _logger.LogDebug("Queued stage via factory {StageType}", typeof(TStage).Name);
   132→            return this;
   133→        }
   134→
   135→        /// <summary>
   136→        /// Registers an observer which receives lifecycle callbacks.
   137→        /// </summary>
   138→        public PipelineBuilder AddObserver(ITransformationObserver observer)
   139→        {
   140→            if (observer is null)
   141→                throw new ArgumentNullException(nameof(observer));
   142→
   143→            EnsureNotBuilt();
   144→            _observers.Add(observer);
   145→            return this;
   146→        }
   147→
   148→        /// <summary>
   149→        /// Builds an immutable pipeline instance. This method is idempotent,
   150→        /// subsequent calls return the same instance.
   151→        /// </summary>
   152→        public IPipeline Build()
   153→        {
   154→            if (_built)
   155→                throw new InvalidOperationException("Pipeline has already been built.");
   156→
   157→            _built = true;
   158→
   159→            // Materialise stages at build-time.
   160→            var stages = _factoryDelegates.Select(f => f(_services)).ToArray();
   161→
   162→            if (stages.Length == 0)
   163→                throw new InvalidOperationException("Cannot build an empty pipeline.");
   164→
   165→            return new BuiltPipeline(
   166→                stages,
   167→                _observers.ToArray(),
   168→                _services.GetRequiredService<ILogger<BuiltPipeline>>());
   169→        }
   170→
   171→        #region Private Helpers
   172→        private void EnsureNotBuilt()
   173→        {
   174→            if (_built)
   175→                throw new InvalidOperationException("Pipeline has already been built and cannot be modified.");
   176→        }
   177→        #endregion
   178→
   179→        #region Inner Classes
   180→
   181→        /// <summary>
   182→        /// Concrete pipeline produced by the <see cref="PipelineBuilder"/>.
   183→        /// </summary>
   184→        private sealed class BuiltPipeline : IPipeline
   185→        {
   186→            private readonly IReadOnlyList<IPipelineStage> _stages;
   187→            private readonly IReadOnlyList<ITransformationObserver> _observers;
   188→            private readonly ILogger<BuiltPipeline> _logger;
   189→
   190→            public BuiltPipeline(
   191→                IReadOnlyList<IPipelineStage> stages,
   192→                IReadOnlyList<ITransformationObserver> observers,
   193→                ILogger<BuiltPipeline> logger)
   194→            {
   195→                _stages = stages;
   196→                _observers = observers;
   197→                _logger = logger;
   198→            }
   199→
   200→            public Task<IAsyncEnumerable<PigmentFrame>> ExecuteAsync(
   201→                IAsyncEnumerable<PigmentFrame> source,
   202→                CancellationToken cancellationToken = default)
   203→            {
   204→                if (source == null)
   205→                    throw new ArgumentNullException(nameof(source));
   206→
   207→                return Task.FromResult(RunInternalAsync(source, cancellationToken));
   208→            }
   209→
   210→            private async IAsyncEnumerable<PigmentFrame> RunInternalAsync(
   211→                IAsyncEnumerable<PigmentFrame> upstream,
   212→                [EnumeratorCancellation] CancellationToken cancellationToken)
   213→            {
   214→                IAsyncEnumerable<PigmentFrame> current = upstream;
   215→
   216→                foreach (var stage in _stages)
   217→                {
   218→                    cancellationToken.ThrowIfCancellationRequested();
   219→
   220→                    await NotifyStartedAsync(stage, cancellationToken).ConfigureAwait(false);
   221→
   222→                    try
   223→                    {
   224→                        current = await stage.ProcessAsync(current, cancellationToken)
   225→                                             .ConfigureAwait(false);
   226→
   227→                        await NotifyCompletedAsync(stage, cancellationToken).ConfigureAwait(false);
   228→                    }
   229→                    catch (Exception ex)
   230→                    {
   231→                        _logger.LogError(ex, "Stage {StageName} threw an exception.", stage.Name);
   232→                        await NotifyErrorAsync(stage, ex, cancellationToken).ConfigureAwait(false);
   233→                        throw; // Bubble up so compensating transactions can kick in upstream.
   234→                    }
   235→                }
   236→
   237→                await foreach (var frame in current.WithCancellation(cancellationToken)
   238→                                                   .ConfigureAwait(false))
   239→                {
   240→                    yield return frame;
   241→                }
   242→            }
   243→
   244→            #region Observer Helpers
   245→
   246→            private Task NotifyStartedAsync(IPipelineStage stage, CancellationToken token)
   247→                => BroadcastAsync(o => o.OnStageStartedAsync(stage.Name, token));
   248→
   249→            private Task NotifyCompletedAsync(IPipelineStage stage, CancellationToken token)
   250→                => BroadcastAsync(o => o.OnStageCompletedAsync(stage.Name, token));
   251→
   252→            private Task NotifyErrorAsync(IPipelineStage stage, Exception ex, CancellationToken token)
   253→                => BroadcastAsync(o => o.OnStageErrorAsync(stage.Name, ex, token));
   254→
   255→            private Task BroadcastAsync(Func<ITransformationObserver, Task> action)
   256→            {
   257→                if (_observers.Count == 0)
   258→                    return Task.CompletedTask;
   259→
   260→                var tasks = new List<Task>(_observers.Count);
   261→
   262→                foreach (var observer in _observers)
   263→                {
   264→                    try
   265→                    {
   266→                        tasks.Add(action(observer));
   267→                    }
   268→                    catch (Exception ex)
   269→                    {
   270→                        // Ensure an observer failure does not take down the pipeline.
   271→                        _logger.LogWarning(ex, "Observer {ObserverType} threw an exception.", observer.GetType().Name);
   272→                    }
   273→                }
   274→
   275→                return Task.WhenAll(tasks);
   276→            }
   277→
   278→            #endregion
   279→        }
   280→
   281→        #endregion
   282→    }
