   286→    /// <summary>
   287→    /// Sample stage that enriches frames by injecting a new column.
   288→    /// </summary>
   289→    public sealed class EnrichmentStage : IPipelineStage
   290→    {
   291→        private readonly ILogger<EnrichmentStage> _logger;
   292→
   293→        public EnrichmentStage(ILogger<EnrichmentStage> logger)
   294→        {
   295→            _logger = logger;
   296→        }
   297→
   298→        public string Name => nameof(EnrichmentStage);
   299→
   300→        public ValueTask<IAsyncEnumerable<PigmentFrame>> ProcessAsync(IAsyncEnumerable<PigmentFrame> input,
   301→            CancellationToken cancellationToken = default)
   302→        {
   303→            async IAsyncEnumerable<PigmentFrame> Impl(
   304→                IAsyncEnumerable<PigmentFrame> src,
   305→                [EnumeratorCancellation] CancellationToken token)
   306→            {
   307→                await foreach (var frame in src.WithCancellation(token).ConfigureAwait(false))
   308→                {
   309→                    var cols = new Dictionary<string, object?>(frame.Columns)
   310→                    {
   311→                        ["enriched_at"] = DateTimeOffset.UtcNow
   312→                    };
   313→
   314→                    _logger.LogTrace("Frame {FrameId} enriched.", frame.Id);
   315→
   316→                    yield return frame with { Columns = new ReadOnlyDictionary<string, object?>(cols) };
   317→                }
   318→            }
   319→
   320→            return new ValueTask<IAsyncEnumerable<PigmentFrame>>(Impl(input, cancellationToken));
   321→        }
   322→    }
