   328→    public sealed class QualityCheckStage : IPipelineStage
   329→    {
   330→        private readonly ILogger<QualityCheckStage> _logger;
   331→
   332→        public QualityCheckStage(ILogger<QualityCheckStage> logger)
   333→        {
   334→            _logger = logger;
   335→        }
   336→
   337→        public string Name => nameof(QualityCheckStage);
   338→
   339→        public ValueTask<IAsyncEnumerable<PigmentFrame>> ProcessAsync(
   340→            IAsyncEnumerable<PigmentFrame> input,
   341→            CancellationToken cancellationToken = default)
   342→        {
   343→            async IAsyncEnumerable<PigmentFrame> Impl(
