     6→namespace PaletteStream.Transformer.Observers
     7→{
     8→    /// <summary>
     9→    /// Observes <see cref="TransformationEvent"/>s emitted from the Transformer pipeline
    10→    /// and forwards aggregated telemetry to a metrics back-end as well as structured logs.
    11→    /// </summary>
    12→    /// <remarks>
    13→    /// The observer is **thread-safe** and inexpensive; it is designed to be reused
    14→    /// for multiple observable subscriptions within the ETL microservice.
    15→    ///
    16→    /// Typical usage:
    17→    /// <code>
    18→    ///   var observer = new MonitoringObserver(logger, metrics);
    19→    ///   observableTransformationEvents.Subscribe(observer);
    20→    /// </code>
    21→    /// </remarks>
    22→    public sealed class MonitoringObserver : IObserver<TransformationEvent>, IDisposable
    23→    {
    24→        private readonly ILogger<MonitoringObserver> _logger;
    25→        private readonly IMetricsRecorder _metrics;
    26→        private int _hasCompleted;
    27→
    28→        public MonitoringObserver(
    29→            ILogger<MonitoringObserver> logger,
    30→            IMetricsRecorder metricsRecorder)
    31→        {
    32→            _logger  = logger  ?? throw new ArgumentNullException(nameof(logger));
    33→            _metrics = metricsRecorder ?? throw new ArgumentNullException(nameof(metricsRecorder));
    34→        }
    35→
    36→        #region IObserver
    37→
    38→        public void OnNext(TransformationEvent value)
    39→        {
    40→            if (value is null) return;
    41→
    42→            // Emit structured log
    43→            _logger.LogInformation(
    44→                "Transformer {Transformer} processed {Input} records (Output = {Output}) in {ElapsedMs:n0} ms [Success = {Success}] {@Event}",
    45→                value.TransformerName,
    46→                value.InputRecords,
    47→                value.OutputRecords,
    48→                value.Duration.TotalMilliseconds,
    49→                value.IsSuccess,
    50→                value);
    51→
    52→            // Emit metrics
    53→            var commonTags = new[]
    54→            {
    55→                ("pipeline",  value.Pipeline),
    56→                ("transformer", value.TransformerName),
    57→                ("success", value.IsSuccess.ToString().ToLowerInvariant())
    58→            };
    59→
    60→            _metrics.IncrementCounter("transformations_total", 1, commonTags);
    61→
    62→            // Record duration as histogram (seconds)
    63→            _metrics.RecordHistogram("transformation_duration_seconds",
    64→                value.Duration.TotalSeconds, commonTags);
    65→
    66→            // Record throughput gauges (records / s)
    67→            if (value.Duration > TimeSpan.Zero)
    68→            {
    69→                var throughputIn  = value.InputRecords  / value.Duration.TotalSeconds;
    70→                var throughputOut = value.OutputRecords / value.Duration.TotalSeconds;
    71→
    72→                _metrics.RecordGauge("transformation_throughput_in_records_per_second",
    73→                    throughputIn,  commonTags);
    74→                _metrics.RecordGauge("transformation_throughput_out_records_per_second",
    75→                    throughputOut, commonTags);
    76→            }
    77→
    78→            if (!value.IsSuccess && !string.IsNullOrWhiteSpace(value.ErrorMessage))
    79→            {
    80→                _metrics.IncrementCounter("transformation_failures_total", 1, commonTags);
    81→            }
    82→        }
    83→
    84→        public void OnError(Exception error)
    85→        {
    86→            _logger.LogError(error, "An error occurred in the transformation observable.");
    87→            _metrics.IncrementCounter("transformation_observer_errors_total", 1,
    88→                ("component", nameof(MonitoringObserver)));
    89→        }
    90→
    91→        public void OnCompleted()
    92→        {
    93→            // Ensure we only log completion once in case multiple observables share the same observer.
    94→            if (Interlocked.Exchange(ref _hasCompleted, 1) == 0)
    95→            {
    96→                _logger.LogInformation("Transformation event stream completed.");
    97→            }
    98→        }
